module reg_file(
    input clk,
    input we,
    input [2:0] waddr,
    input [2:0] raddr1,
    input [2:0] raddr2,
    input [15:0] wdata,

    output [15:0] rdata1,
    output [15:0] rdata2
);

reg [15:0] unused_regs [7:0];

always @(posedge clk)
begin
    if (we)
        unused_regs[waddr] <= wdata;
end

assign rdata1 = unused_regs[raddr1];
assign rdata2 = unused_regs[raddr2];

endmodule
